import{_ as t,o,c as s,a2 as i}from"./chunks/framework.BYlK8ftn.js";const g=JSON.parse('{"title":"0001 — Hosting for generated binary 3D assets","description":"","frontmatter":{},"headers":[],"relativePath":"decisions/0001-asset-hosting.md","filePath":"decisions/0001-asset-hosting.md","lastUpdated":1781956454000}'),r={name:"decisions/0001-asset-hosting.md"};function a(n,e,d,l,c,h){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_0001-—-hosting-for-generated-binary-3d-assets" tabindex="-1">0001 — Hosting for generated binary 3D assets <a class="header-anchor" href="#_0001-—-hosting-for-generated-binary-3d-assets" aria-label="Permalink to &quot;0001 — Hosting for generated binary 3D assets&quot;">​</a></h1><ul><li>Status: Accepted</li><li>Date: 2026-06-20</li><li>Deciders: Daedalus (CTO)</li><li>Context issue: <a href="https://github.com/Fl0p/korovany" target="_blank" rel="noreferrer">FLO-257</a> (from FLO-256, the Meshy pipeline)</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The <code>meshy-3d</code> skill (<code>tools/meshy-3d/</code>) generates web-ready GLB models for the game. A preview (untextured) GLB is ~1 MB; textured/refined models are larger. These binaries need a home that:</p><ul><li>keeps the deploy story trivial (one repo → Cloudflare Pages, no second service);</li><li>versions assets alongside the code that references them;</li><li>does not bloat the git object store so every future clone pays for old revisions;</li><li>survives without per-asset signed-URL bookkeeping.</li></ul><p>The FLO-253 scaffold already wired a comprehensive <code>.gitattributes</code> routing <code>*.glb</code>, textures, audio, and fonts through <strong>Git LFS</strong>. This ADR ratifies or overrides that default.</p><h2 id="options-considered" tabindex="-1">Options considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options considered&quot;">​</a></h2><ol><li><strong>Commit binaries directly to the git object store.</strong> Simplest, but every revision of every asset lives in history forever — clone size grows without bound. Rejected (violates &quot;schema/history is forever&quot;).</li><li><strong>Git LFS</strong> (the scaffold default). Binaries are stored as LFS pointers in git and fetched from LFS on checkout. History stays lean; assets are still versioned with the code; one repo, one deploy. Cost: contributors run <code>git lfs install</code> once, CI checkout must pull LFS, and GitHub&#39;s free LFS tier is 1 GiB storage + 1 GiB/mo bandwidth.</li><li><strong>External object store / CDN (Cloudflare R2) + a manifest.</strong> No git bloat, scales to large libraries. Cost: a second system to provision and authenticate, a manifest to keep in sync, and assets decoupled from the commit that needs them. Premature for the MVP.</li></ol><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Ratify Git LFS (option 2)</strong> as the home for binary game assets for the MVP and early game phase. Web-ready GLBs live in <strong><code>public/models/</code></strong>, tracked by LFS.</p><ul><li><code>public/</code> is copied verbatim into the Vite build, so a model at <code>public/models/chest.glb</code> is served by Cloudflare&#39;s CDN at <code>/models/chest.glb</code> and loaded at runtime by the Babylon loader (see ADR 0002). End-user download bandwidth is served by Cloudflare, <strong>not</strong> GitHub LFS — LFS bandwidth is only spent on CI checkouts (one per deploy).</li><li>The <code>meshy-3d</code> skill writes to a scratch dir (<code>tools/meshy-3d/out/</code>, gitignored). Workflow: generate → review poly count / size / textures against budget → move the approved GLB into <code>public/models/</code> (LFS picks it up via <code>.gitattributes</code>).</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li><strong>CI must pull LFS.</strong> <code>actions/checkout</code> defaults to pointer files only; the deploy workflow&#39;s checkout now sets <code>lfs: true</code>, otherwise the build would ship broken pointer files. (Fixed in this change.)</li><li><strong>Contributors run <code>git lfs install</code> once</strong> before cloning; documented in the README. Cloudflare Pages, when it builds directly from the repo, also needs LFS enabled — but our deploy builds in GitHub Actions and uploads <code>dist</code>, so this is covered by the CI checkout fix.</li><li><strong>Asset budget guardrail.</strong> Keep committed GLBs web-optimized: prefer Meshy&#39;s remeshed output, target ≤ ~2–3 MB per model, and use Draco/meshopt geometry compression + KTX2 textures when we add textured assets.</li><li><strong>Migration trigger (escape hatch).</strong> Move to Cloudflare R2 + a manifest when total LFS storage approaches the free 1 GiB tier, or when we accumulate many large textured variants. This is reversible: the loader takes a URL, so swapping <code>/models/x.glb</code> for an R2 URL is a config change, not a rewrite.</li></ul>',13)])])}const p=t(r,[["render",a]]);export{g as __pageData,p as default};
